import { Link } from "react-router-dom";

function HomePage() {
  const storedUser = localStorage.getItem("user");
  const user = storedUser ? JSON.parse(storedUser) : null;

  return (
    <div
      style={{
        minHeight: "100vh",
        background: "linear-gradient(135deg, #6a11cb, #2575fc)",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        color: "white",
        textAlign: "center",
        padding: "20px",
      }}
    >
      <h1 style={{ fontSize: "3rem", marginBottom: "10px" }}>
        Cloud Event Management Platform
      </h1>

      <p style={{ fontSize: "1.2rem", marginBottom: "30px" }}>
        Manage events, register users, and experience a modern cloud-based event system.
      </p>

      {user && (
        <p
          style={{
            background: "rgba(255,255,255,0.2)",
            padding: "10px 20px",
            borderRadius: "20px",
            marginBottom: "30px",
          }}
        >
          Welcome back, <strong>{user.name}</strong> ({user.role})
        </p>
      )}

      <div>
        {/* View Events */}
        <Link to="/events">
          <button style={buttonStyle("#ffcc70")}>View Events</button>
        </Link>

        {/* Login */}
        {!user && (
          <Link to="/login">
            <button style={buttonStyle("#70e1f5")}>Login</button>
          </Link>
        )}

        {/* Signup */}
        {!user && (
          <Link to="/register">
            <button style={buttonStyle("#ffd194")}>Signup</button>
          </Link>
        )}

        {/* User only */}
        {user && user.role === "user" && (
          <Link to="/my-registrations">
            <button style={buttonStyle("#c2ffd8")}>
              My Registrations
            </button>
          </Link>
        )}

        {/* Admin only */}
        {user && user.role === "admin" && (
          <Link to="/create-event">
            <button style={buttonStyle("#fff3b0")}>
              Create Event
            </button>
          </Link>
        )}
      </div>
    </div>
  );
}

const buttonStyle = (bgColor) => ({
  margin: "10px",
  padding: "14px 24px",
  border: "none",
  borderRadius: "10px",
  backgroundColor: bgColor,
  color: "#222",
  fontWeight: "bold",
  cursor: "pointer",
  fontSize: "1rem",
});

export default HomePage;
